const rows = $input.all().map(i => i.json);

let ingresos = 0, gastos = 0;
const byDay = {};

for (const r of rows) {
  const meta = r.metadata || {};
  const amt = parseFloat(meta.amount || 0);
  const day = (r.created_at || '').slice(0,10);
  if (!byDay[day]) byDay[day] = { in: 0, out: 0 };
  if (r.type === 'income') { ingresos += amt; byDay[day].in += amt; }
  else { gastos += amt; byDay[day].out += amt; }
}

const balance = ingresos - gastos;
const sign = balance >= 0 ? '🟢' : '🔴';

const today = new Date().toLocaleDateString('es-MX', { weekday:'long', day:'numeric', month:'long' });

const dayLines = Object.entries(byDay)
  .sort(([a],[b]) => b.localeCompare(a))
  .slice(0,5)
  .map(([d,[,v]]) => {
    const vals = byDay[d];
    return `📅 ${d}: +$${vals.in.toFixed(2)} / -$${vals.out.toFixed(2)}`;
  }).join('\n');

const mensaje = [
  `🧠 *Nexus OS — Resumen Financiero*`,
  `📆 ${today}`,
  ``,
  `💰 Ingresos (7d): $${ingresos.toFixed(2)}`,
  `💸 Gastos (7d):  $${gastos.toFixed(2)}`,
  `${sign} Balance:      $${balance.toFixed(2)}`,
  ``,
  `*Últimos días:*`,
  dayLines || 'Sin transacciones',
  ``,
  `🔗 Ver detalle: nexus-os-chi.vercel.app/app`,
].join('\n');

return [{ json: { mensaje, ingresos, gastos, balance } }];
